<?php require_once dirname(__DIR__, 2).'/functions.php'; $settings=$settings ?? ($block['settings'] ?? []); ?>
<?php $posts=omh_block_posts($settings,5); $main=$posts[0] ?? null; ?><section class="omh-latest"><div class="omh-section-title"><h2><?=omh_e($settings['title'] ?? 'SON HABERLER')?></h2></div><?php if($main): ?><div class="omh-latest-layout"><a class="omh-latest-main" href="<?=omh_e(omh_post_url($main))?>"><img src="<?=omh_e(omh_img($main))?>" alt=""><h3><?=omh_e($main['title'])?></h3><span><?=omh_e(omh_date($main))?></span></a><div class="omh-latest-list"><?php foreach(array_slice($posts,1) as $p): ?><a href="<?=omh_e(omh_post_url($p))?>"><img src="<?=omh_e(omh_img($p))?>" alt=""><strong><?=omh_e($p['title'])?></strong><small><?=omh_e(omh_date($p))?></small></a><?php endforeach; ?></div></div><?php else: ?><div class="omh-empty">Henüz haber eklenmemiş.</div><?php endif; ?></section>
